import { Race } from '@firestone-hs/reference-data';
import { BoardEntity } from '../../../board-entity';
import { CardIds } from '../../../services/card-ids';
import { pickMultipleRandom, pickRandom } from '../../../services/utils';
import { OnAttackInput } from '../../../simulation/on-attack';
import { modifyStats } from '../../../simulation/stats';
import { hasCorrectTribe } from '../../../utils';
import { RallyCard } from '../../card.interface';

export const Dramaloc: RallyCard = {
	cardIds: [CardIds.Dramaloc_BG34_143, CardIds.Dramaloc_BG34_143_G],
	rally: (
		minion: BoardEntity,
		input: OnAttackInput,
	): {
		dmgDoneByAttacker: number;
		dmgDoneByDefender: number;
	} => {
		if (!input.attackingHero?.hand) {
			return { dmgDoneByAttacker: 0, dmgDoneByDefender: 0 };
		}
		const mult = minion.cardId === CardIds.Dramaloc_BG34_143_G ? 2 : 1;
		const highestAttackInHand = input.attackingHero.hand
			.filter((e) => e.attack != null && !!e.cardId)
			.sort((a, b) => b.attack - a.attack)[0]?.attack;
		const statsSource = pickRandom(
			input.attackingHero.hand.filter((e) => e.attack == highestAttackInHand && !!e.cardId),
		);
		if (!!statsSource) {
			for (let i = 0; i < mult; i++) {
				const candidates = input.attackingBoard.filter(
					(e) =>
						e !== minion &&
						hasCorrectTribe(
							e,
							input.attackingHero,
							Race.MURLOC,
							input.gameState.anomalies,
							input.gameState.allCards,
						),
				);
				const targets = pickMultipleRandom(candidates, 2);
				for (const target of targets) {
					modifyStats(
						target,
						minion,
						statsSource.attack,
						statsSource.health,
						input.attackingBoard,
						input.attackingHero,
						input.gameState,
					);
				}
			}
		}

		return { dmgDoneByAttacker: 0, dmgDoneByDefender: 0 };
	},
};
